// firebase-messaging-sw.js — minimal stub for A5.1.
//
// Firebase Cloud Messaging auto-registers this file at the origin root
// when the SDK initialises. For A5.1 (token collection only) we just
// need it to exist so the Messaging SDK doesn't 404 — no background
// push handler is wired yet because the daily-reminder Cloud Function
// (A5.2) hasn't been built. Once it lands, we'll import + initialise
// firebase-messaging compat here and call onBackgroundMessage to
// render the system notification.
//
// Note: this SW lives at a different scope from the Workbox SW
// generated by vite-plugin-pwa (/sw.js). They coexist — Workbox owns
// the cache, Messaging owns push. Don't merge them; both have well-
// defined lifecycles that get tangled if you try.
self.addEventListener('install', () => self.skipWaiting())
self.addEventListener('activate', (event) => event.waitUntil(self.clients.claim()))
